"""### 📦 Тестовый пакет для единого репликатора / TFS

Загружает тестовые ZIP-пакеты в S3 с актуальными таймштампами.
По умолчанию используются встроенные тестовые данные (3 части, 36/37/38 строк).
Содержимое и схему можно переопределить через параметры `parts` и `meta`.

| Параметр       | Описание                                                                          |
|----------------|-----------------------------------------------------------------------------------|
| `prefix`       | Префикс имени файла *(default: `hrplatform_datalab`)*                             |
| `table_name`   | Таблица в формате `schema__table` *(default: `learning__lc_items_opened`)*        |
| `s3_prefix`    | Папка в бакете, без слэша в конце *(default: пусто — корень бакета)*              |
| `bucket`       | S3 бакет *(зависит от стенда)*                                                    |
| `conn_id`      | Airflow S3 connection ID *(зависит от стенда)*                                    |
| `meta`         | Содержимое `.meta` файла (JSON схема таблицы)                                     |
| `parts`        | Список строк CSV; повтор заголовка обозначает начало новой части                  |
"""

from __future__ import annotations
import base64
import json
import logging
import os
import zipfile
from io import BytesIO

import pendulum

logger = logging.getLogger("airflow.task")
from airflow.decorators import dag, task
from airflow.models import Param
from airflow.providers.amazon.aws.hooks.s3 import S3Hook


_META = '{"schema_name": "learning", "table_name": "lc_items_opened", "strategy": "FULL_UK", "PK": [], "UK": ["person_uuid", "item_id"], "params": {"separation": "\\t", "escapesymbol": "\\""}, "columns": [{"column_name": "export_time", "source_type": "TIMESTAMP", "length": null, "notnull": false, "precision": null, "scale": null, "description": "Дата выгрузки"}, {"column_name": "insert_time", "source_type": "TIMESTAMP", "length": null, "notnull": false, "precision": null, "scale": null, "description": "Дата вставки"}, {"column_name": "header_id", "source_type": "STRING", "length": null, "notnull": false, "precision": 38, "scale": 10, "description": "Уникальный идентификатор ивента"}, {"column_name": "header_person_id", "source_type": "STRING", "length": 4096, "notnull": false, "precision": null, "scale": null, "description": "ID сотрудника, изучающего материал"}, {"column_name": "header_event_type", "source_type": "STRING", "length": 4096, "notnull": false, "precision": null, "scale": null, "description": "Тип ивента"}, {"column_name": "header_created_dt", "source_type": "DATE", "length": 4096, "notnull": false, "precision": null, "scale": null, "description": "Дата генерации ивента"}, {"column_name": "item_id", "source_type": "INT", "length": 25, "notnull": true, "precision": null, "scale": null, "description": "ID материала"}, {"column_name": "person_uuid", "source_type": "INT", "length": 25, "notnull": true, "precision": null, "scale": null, "description": "ID сотрудника, изучающего материал"}, {"column_name": "tenant", "source_type": "STRING", "length": 4096, "notnull": false, "precision": null, "scale": null, "description": "тенант"}, {"column_name": "company", "source_type": "STRING", "length": 4096, "notnull": false, "precision": null, "scale": null, "description": "компания"}, {"column_name": "ctl_action", "source_type": "VARCHAR", "length": 10, "notnull": false, "precision": null, "scale": null, "description": null}, {"column_name": "ctl_validfrom", "source_type": "TIMESTAMP", "length": null, "notnull": false, "precision": null, "scale": null, "description": null}]}'

# base64(json список всех строк CSV, повтор заголовка = новая часть)
_PARTS = ""
_PARTS_LINES: list[str] = json.loads(base64.b64decode(_PARTS))

if os.getenv("AIRFLOW__CTL_PIN"):
    def_conn_id = "s3-archive"
    def_bucket = "edpetl-test"
else:
    def_conn_id = "s3-tfs-hrplt"
    def_bucket = "tfshrplt"


@dag(
    doc_md=__doc__,
    default_args={"owner": "DataLab (CI02420667)", "retries": 0},
    owner_links={"DataLab (CI02420667)": "https://confluence.sberbank.ru/display/HRTECH/DataLab"},
    start_date=pendulum.datetime(2025, 8, 7, tz=pendulum.UTC),
    tags=["DataLab", "tools", "test"],
    catchup=False,
    is_paused_upon_creation=True,
    max_active_runs=1,
    schedule_interval=None,
    params={
        "prefix": Param("hrplatform_datalab", type="string", description="Префикс имени файла"),
        "table_name": Param("learning__lc_items_opened", type="string", description="Таблица в формате schema__table"),
        "s3_prefix": Param("", type=["string", "null"], description="Папка в бакете (без слэша в конце)"),
        "bucket": Param(def_bucket, type="string", description="S3 бакет"),
        "conn_id": Param(def_conn_id, type="string", description="Airflow S3 connection ID"),
        "meta": Param(_META, type="string", description="Содержимое .meta файла (JSON схема)"),
        "parts": Param(
            _PARTS_LINES,
            type="array",
            description="Список строк CSV (повтор заголовка = новая часть)",
        ),
    },
)
def tools_test_package():

    @task(task_id="upload")
    def upload(**context):
        p = context["params"]
        prefix = p["prefix"]
        full_table = p["table_name"]
        schema, _, table_name = full_table.partition("__")
        s3_prefix = (p["s3_prefix"] or "").rstrip("/")
        bucket = p["bucket"]
        lines = p["parts"]
        if isinstance(lines, str):
            lines = lines.splitlines()

        header = lines[0]

        # Определяем разделитель из метаданных (по умолчанию табуляция)
        sep = "\t"
        try:
            meta_dict = json.loads(p["meta"])
            sep_raw = meta_dict.get("params", {}).get("separation", "\t")
            # Обрабатываем экранированную табуляцию из JSON
            sep = "\t" if sep_raw == "\\t" else sep_raw
        except Exception:
            pass

        expected_cols = len(header.split(sep))

        parts, cur = [], []
        for i, line in enumerate(lines):
            if line == header and cur:
                parts.append(cur)
                cur = []

            # Валидация количества колонок
            cols = len(line.split(sep))
            if cols != expected_cols:
                raise ValueError(
                    f"Ошибка валидации данных: строка {i+1} содержит {cols} колонок, "
                    f"ожидалось {expected_cols}. Разделитель: {sep!r}. Текст строки: {line!r}"
                )

            cur.append(line)
        if cur:
            parts.append(cur)
        total = len(parts)

        base_ts = pendulum.now("UTC")
        hook = S3Hook(aws_conn_id=p["conn_id"])
        meta_bytes = p["meta"].encode()
        uploaded = []

        for i, part_lines in enumerate(parts):
            rows = len(part_lines) - 1
            part = i + 1
            # Добавляем финальный перенос строки, чтобы сохранить табуляцию в последней колонке
            csv_content = "\n".join(part_lines) + "\n"
            csv_bytes = csv_content.encode()

            inner_ts = base_ts.add(seconds=i * 2).format("YYYYMMDDHHmmss")
            tkt_ts   = base_ts.add(seconds=i * 2 + 1).format("YYYYMMDDHHmmss")
            outer_ts = base_ts.add(seconds=i * 2 + 2).format("YYYYMMDDHHmmss")

            csv_name  = f"{schema}__{table_name}__{inner_ts}__{part}_{total}_{rows}.csv"
            meta_name = f"{schema}__{table_name}__{inner_ts}__{part}_{total}_{rows}.meta"
            tkt_name  = f"{prefix}__{tkt_ts}.tkt"
            tkt_bytes = f"{csv_name};{rows}".encode()
            zip_name  = f"{prefix}__{outer_ts}__{table_name}__{part}_{total}_{rows}.csv.zip"

            buf = BytesIO()
            with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
                zf.writestr(meta_name, meta_bytes)
                zf.writestr(tkt_name, tkt_bytes)
                zf.writestr(csv_name, csv_bytes)
            buf.seek(0)

            s3_key = f"{s3_prefix}/{zip_name}" if s3_prefix else zip_name
            hook.load_bytes(buf.getvalue(), key=s3_key, bucket_name=bucket, replace=True)
            uploaded.append(zip_name)

        # итоговый .tkt: список всех zip-файлов, ts = last_outer_ts + 1s
        summary_ts = base_ts.add(seconds=(total - 1) * 2 + 3).format("YYYYMMDDHHmmss")
        summary_tkt_name = f"{prefix}__{summary_ts}.tkt"
        summary_tkt_bytes = "\n".join(uploaded).encode()
        hook.load_bytes(
            summary_tkt_bytes,
            key=f"{s3_prefix}/{summary_tkt_name}" if s3_prefix else summary_tkt_name,
            bucket_name=bucket,
            replace=True,
        )

        for name in uploaded:
            logger.info("✅ uploaded: %s/%s", s3_prefix, name)
        logger.info("✅ summary tkt: %s/%s", s3_prefix, summary_tkt_name)

        return uploaded


    upload()


ENV_STAND = os.getenv("ENV_STAND", "").strip().lower()

if ENV_STAND == "prom":
    logger.warning("DAG tools_test_package is disabled on 'prom' stand. Skipping DAG registration.")
else:
    tools_test_package()
